import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip, Divider } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface TopDeal {
  item: string;
  originalPrice: number;
  discountedPrice: number;
  percentageOff: number;
  expiry: string;
}

interface DealTrend {
  day: string;
  deals: number;
}

interface DealsData {
  topDeals: TopDeal[];
  dealTrend: DealTrend[];
}

export default function Widget() {
  const { topDeals, dealTrend } = response.data as DealsData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#303030', color: '#FFFFFF' }} elevation={3}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Typography variant="h6" fontWeight={600} sx={{ color: '#FF5722' }}>
            Top Deals
          </Typography>

          <Stack spacing={1.5}>
            {topDeals.map((deal, index) => (
              <Box key={index}>
                <Stack direction="row" justifyContent="space-between" alignItems="center">
                  <Typography variant="body1" fontWeight={500}>
                    {deal.item}
                  </Typography>
                  <Chip label={`-${deal.percentageOff}%`} sx={{ bgcolor: '#FFC107', color: '#000' }} />
                </Stack>
                <Stack direction="row" justifyContent="space-between" alignItems="center">
                  <Typography variant="caption" color="text.secondary">
                    ${deal.discountedPrice.toFixed(2)} <del>${deal.originalPrice.toFixed(2)}</del>
                  </Typography>
                  <Typography variant="caption" color="text.secondary">
                    Expires: {new Date(deal.expiry).toLocaleDateString()}
                  </Typography>
                </Stack>
                {index < topDeals.length - 1 && <Divider sx={{ my: 1 }} />}
              </Box>
            ))}
          </Stack>

          <Typography variant="h6" fontWeight={600} sx={{ color: '#FF5722', mt: 2 }}>
            Deal Trends
          </Typography>

          <BarChart
            height={140}
            series={[
              {
                data: dealTrend.map(d => d.deals),
                color: '#FFC107',
              },
            ]}
            xAxis={[
              {
                data: dealTrend.map(d => d.day),
                scaleType: 'band',
                tickLabelStyle: {
                  fontSize: 11,
                  fill: '#B0BEC5',
                },
              }
            ]}
            margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
            sx={{
              '& .MuiBarElement-root': {
                rx: 4,
              },
            }}
          />
        </Stack>
      </CardContent>
    </Card>
  );
}
